const should = require('should');
const expect = require('chai').expect;
const assert = require('chai').assert;
const PromiseFactory = require('logged-promise');
const async = require('async');
const ModelFactory = require('../../index');

const config = require('../config');
const BlogHelper = require('../helpers/BlogHelper');
const ConfigHelper = require('../helpers/ConfigHelper');

const serviceInit = {
	requestId: "TEST-" + require('uuid/v1')(),
	currentUser: {
		organizationId: 1,
		userId: 1,
		username: 'test@corebit.tech'
	}
};

PromiseFactory.appStart(ConfigHelper.getLogger());

describe("Model Operation CRUD Test", function () {
	this.timeout(150000);
	let blogId;
	let BlogModel;

	before((done) => {
		ModelFactory.appStart(ConfigHelper.getLogger(), config, (db) => {
			async.each(db, (model, cb) => {
				model.sync({force: true}).then(() => {
					cb(null);
				});
			}, () => {
				BlogModel = ModelFactory.init(serviceInit).get('Blog');
				done();
			});
		});
	});

	after((done) => {
		ModelFactory.appStart(ConfigHelper.getLogger(), config, (db) => {
			async.each(db, (model, cb) => {
				model.drop().then(() => {
					cb(null);
				});
			}, done);
		});
	});

	it("It creates new post [create]", (done) => {
		BlogModel
			.create(BlogHelper.createData())
			.then((blog) => {
				blog.should.have.property("id");
				blogId = blog.id;
				done();
			})
			.catch((err) => {
				console.error(err);
			});
	});

	it("It updates a post [update]", (done) => {
		BlogModel
			.update(BlogHelper.updateData(), {
				where: {
					id: blogId
				}
			})
			.then((blog) => {
				blog.should.have.property('instance');
				blog.should.have.property('affectedRowCount');
				blog.instance.title.should.equal(BlogHelper.updateData().title);
				blog.instance.text.should.equal(BlogHelper.updateData().text);
				done();
			})
			.catch((err) => {
				console.error(err);
			});
	});


	it("It selects a post with [findOne]", (done) => {
		BlogModel
			.findOne({
				where: {
					id: blogId
				}
			})
			.then((blog) => {
				blog.should.have.property("id");
				done();
			})
			.catch((err) => {
				console.error(err);
			});
	});


	it("It selects a post with [findById]", (done) => {
		BlogModel
			.findById(blogId)
			.then((blog) => {
				blog.should.have.property("id");
				done();
			});
	});

	it("It counts all posts [findAll]", (done) => {
		BlogModel
			.count({})
			.then((result) => {
				result.should.have.property("rowCount");
				done();
			})
			.catch((err) => {
				console.error(err);
			});
	});

	it("It selects all posts [findAll]", (done) => {
		BlogModel
			.findAll({})
			.then((blogs) => {
				expect(blogs).to.not.be.empty;
				done();
			})
			.catch((err) => {
				console.error(err);
			});
	});



	it("It deletes a post [destroy]", (done) => {
		BlogModel
			.destroy({
				where: {
					id: blogId
				}
			})
			.then((result) => {
				result.should.have.property('affectedRowCount');
				done();
			})
			.catch((err) => {
				console.error(err);
			});
	});

});


describe("Model Operation Parameter Tests", function () {
	this.timeout(150000);

	let BlogModel;

	before((done) => {
		ModelFactory.appStart(ConfigHelper.getLogger(), config, (db) => {
			async.each(db, (model, cb) => {
				model.sync({force: true}).then(() => {
					cb(null);
				});
			}, () => {
				BlogModel = ModelFactory.init(serviceInit).get('Blog');
				done();
			});
		});
	});

	after((done) => {
		ModelFactory.appStart(ConfigHelper.getLogger(), config, (db) => {
			async.each(db, (model, cb) => {
				model.drop().then(() => {
					cb(null);
				});
			}, done);
		});
	});


	it('It calls findOne without parameter', (done) => {
		expect(() => {
			BlogModel.findOne();
		}).to.throw(Error, /findOne: options is null or undefined/);

		done();
	});

	it('It calls findById without parameter', (done) => {
		expect(() => {
			BlogModel.findById();
		}).to.throw(Error, /findById: id is null or undefined/);

		done();
	});

	it('It calls update without updateData', (done) => {
		expect(() => {
			BlogModel.update();
		}).to.throw(Error, /update: update data is null or undefined/);

		done();
	});

	it('It calls destroy without options', (done) => {
		expect(() => {
			BlogModel.destroy();
		}).to.throw(Error, /destroy: opt is null or undefined/);

		done();
	});

	it('It calls create without options', (done) => {
		expect(() => {
			BlogModel.create();
		}).to.throw(Error, /create: createData data is null or undefined/);
		done();
	});

	it('It calls count without options', (done) => {
		expect(() => {
			BlogModel.count();
		}).to.throw(Error, /count: opt is null or undefined/);

		done();
	});
});